import{_ as e,a as t,b as l,c as o}from"./chunks/下载好后的视频.pSSnkGgz.js";import{_ as n,o as i,c as r,a2 as d}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Magnet Transfer","description":"","frontmatter":{},"headers":[],"relativePath":"ta/Other/magnet-transfer.md","filePath":"ta/Other/magnet-transfer.md","lastUpdated":1781962217000}'),s={name:"ta/Other/magnet-transfer.md"};function p(m,a,c,h,u,g){return i(),r("div",null,[...a[0]||(a[0]=[d('<h1 id="magnet-transfer" tabindex="-1">Magnet Transfer <a class="header-anchor" href="#magnet-transfer" aria-label="Permalink to &quot;Magnet Transfer&quot;">​</a></h1><p>Magnet transfer magnet link-இல் இருந்து files download செய்து, நீங்கள் தேர்வு செய்த cloud storage channel-க்கு தானாக upload செய்கிறது.</p><p>anime episodes, videos, archives போன்ற files transfer செய்ய இது உதவும். magnet link paste செய்தால் ImgBed background download task உருவாக்கும். download முடிந்ததும் file ImgBed-க்கு upload ஆகி final link upload list-ல் தெரியும்.</p><p><img src="'+e+'" alt="Magnet transfer" loading="lazy"></p><h2 id="எங்கு-பயன்படுத்துவது" tabindex="-1">எங்கு பயன்படுத்துவது <a class="header-anchor" href="#எங்கு-பயன்படுத்துவது" aria-label="Permalink to &quot;எங்கு பயன்படுத்துவது&quot;">​</a></h2><p>magnet transfer entry homepage upload area-ல் உள்ளது.</p><p>magnet link input box-ல் paste செய்து <code>Transfer</code> தேர்வு செய்து upload செய்யவும்.</p><p><img src="'+t+'" alt="Upload anime" loading="lazy"></p><h2 id="முதல்-பயன்பாட்டுக்கு-முன்" tabindex="-1">முதல் பயன்பாட்டுக்கு முன் <a class="header-anchor" href="#முதல்-பயன்பாட்டுக்கு-முன்" aria-label="Permalink to &quot;முதல் பயன்பாட்டுக்கு முன்&quot;">​</a></h2><p>முதலில் admin panel-ல் magnet transfer configure செய்யவும்.</p><p>பொதுவாக தேவை:</p><ol><li>download task run செய்ய GitHub account.</li><li>Google Drive அல்லது OneDrive போன்ற cloud upload channel.</li><li>target upload directory.</li><li>task timeout.</li></ol><p>settings தயாரான பிறகு homepage-க்கு திரும்பி magnet link paste செய்து transfer தொடங்கலாம்.</p><h2 id="magnet-link-upload-செய்வது" tabindex="-1">Magnet Link Upload செய்வது <a class="header-anchor" href="#magnet-link-upload-செய்வது" aria-label="Permalink to &quot;Magnet Link Upload செய்வது&quot;">​</a></h2><ol><li>homepage upload box-ல் magnet link paste செய்யவும்.</li><li>mode <code>Transfer</code> என confirm செய்யவும்.</li><li>upload கிளிக் செய்யவும்.</li><li>ImgBed magnet task create செய்ய காத்திருக்கவும்.</li><li>task தொடங்கியதும் bottom-right <code>Magnet Tasks</code> floating panel மூலம் progress பார்க்கவும்.</li></ol><p>download மற்றும் upload நேரம் எடுக்கலாம். speed magnet resource, GitHub runtime environment, selected cloud storage channel ஆகியவற்றை சார்ந்தது.</p><p><img src="'+l+'" alt="Magnet downloading" loading="lazy"></p><h2 id="completion-பிறகு" tabindex="-1">Completion பிறகு <a class="header-anchor" href="#completion-பிறகு" aria-label="Permalink to &quot;Completion பிறகு&quot;">​</a></h2><p>task complete ஆன பிறகு upload list file name மற்றும் link காட்டும்.</p><p>videos video preview, images image preview, மற்ற files regular file icon காட்டும்.</p><p><img src="'+o+'" alt="Downloaded video" loading="lazy"></p><p>copy செய்யக்கூடிய link types:</p><table tabindex="0"><thead><tr><th>Link Type</th><th>Use Case</th></tr></thead><tbody><tr><td>Original link</td><td>direct file access</td></tr><tr><td>Markdown</td><td>Markdown posts அல்லது notes</td></tr><tr><td>HTML</td><td>web page code</td></tr><tr><td>BBCode</td><td>BBCode support forums</td></tr></tbody></table><h2 id="magnet-task-panel" tabindex="-1">Magnet Task Panel <a class="header-anchor" href="#magnet-task-panel" aria-label="Permalink to &quot;Magnet Task Panel&quot;">​</a></h2><p>bottom-right magnet task panel task count, task name, progress, final status காட்டும்.</p><p>Common states:</p><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th></tr></thead><tbody><tr><td>Waiting</td><td>task create ஆகி run காத்திருக்கிறது.</td></tr><tr><td>Downloading</td><td>magnet resource download ஆகிறது.</td></tr><tr><td>Uploading</td><td>file download முடிந்து cloud storage-க்கு upload ஆகிறது.</td></tr><tr><td>Completed</td><td>upload வெற்றி; link copy செய்யலாம்.</td></tr><tr><td>Failed</td><td>task வெற்றிகரமாக முடியவில்லை. message பார்த்து மீண்டும் முயற்சி செய்யவும்.</td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>magnet link multiple files கொண்டிருந்தால் ImgBed display-க்கு main completed file முன்னுரிமை தரும்.</li><li>large files அதிக நேரம் எடுக்கும். page refresh செய்வதற்கு முன் task முடியும் வரை காத்திருக்கவும்.</li><li>magnet resource-க்கு available peers இல்லாவிட்டால் மிகவும் slow அல்லது fail ஆகலாம்.</li><li>cloud account quota முடிந்தால், authorization expired என்றால், அல்லது upload directory தவறாக இருந்தால் task fail ஆகலாம்.</li><li>upload complete ஆன பிறகு video preview சில seconds எடுக்கலாம்.</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="magnet-link-paste-செய்த-பிறகு-எதுவும்-தொடங்கவில்லை" tabindex="-1">Magnet Link Paste செய்த பிறகு எதுவும் தொடங்கவில்லை <a class="header-anchor" href="#magnet-link-paste-செய்த-பிறகு-எதுவும்-தொடங்கவில்லை" aria-label="Permalink to &quot;Magnet Link Paste செய்த பிறகு எதுவும் தொடங்கவில்லை&quot;">​</a></h3><p>admin panel-ல் magnet transfer enabled உள்ளதா, usable GitHub account மற்றும் cloud channel selected உள்ளதா confirm செய்யவும்.</p><h3 id="download-எப்போதும்-slow" tabindex="-1">Download எப்போதும் Slow <a class="header-anchor" href="#download-எப்போதும்-slow" aria-label="Permalink to &quot;Download எப்போதும் Slow&quot;">​</a></h3><p>magnet speed resource-ஐ சார்ந்தது. available peers இல்லையெனில் download மிகவும் slow அல்லது முடியாததாக இருக்கலாம்.</p><h3 id="upload-பிறகு-preview-இல்லை" tabindex="-1">Upload பிறகு Preview இல்லை <a class="header-anchor" href="#upload-பிறகு-preview-இல்லை" aria-label="Permalink to &quot;Upload பிறகு Preview இல்லை&quot;">​</a></h3><p>முதலில் file link திறக்கிறதா confirm செய்யவும். video files browser-ல் load ஆக சிறிது நேரம் எடுக்கலாம்; அல்லது link நேரடியாக திறக்கலாம்.</p><h3 id="task-fail-ஆனால்-என்ன-பார்க்க-வேண்டும்" tabindex="-1">Task Fail ஆனால் என்ன பார்க்க வேண்டும்? <a class="header-anchor" href="#task-fail-ஆனால்-என்ன-பார்க்க-வேண்டும்" aria-label="Permalink to &quot;Task Fail ஆனால் என்ன பார்க்க வேண்டும்?&quot;">​</a></h3><p>magnet link valid ஆ, cloud channel வேலை செய்கிறதா, upload directory சரியா என்று பார்க்கவும். பிறகு task மீண்டும் submit செய்யவும்.</p>',38)])])}const w=n(s,[["render",p]]);export{b as __pageData,w as default};
